class Solution:
    def zigzagLevelOrder(self, root: Optional[TreeNode]) -> List[List[int]]:
        if not root: return []
        res, q, left = [], deque([root]), True
        while q:
            row, n = [], len(q)
            for _ in range(n):
                node = q.popleft()
                row.append(node.val)
                if node.left: q.append(node.left)
                if node.right: q.append(node.right)
            if not left: row.reverse()
            res.append(row); left = not left
        return res

