class Solution {
public:
    vector<vector<int>> zigzagLevelOrder(TreeNode* root) {
        vector<vector<int>> res;
        if (!root) return res;
        queue<TreeNode*> q; q.push(root); bool ltr = true;
        while (!q.empty()) {
            int n = q.size(); vector<int> row(n);
            for (int i = 0; i < n; i++) {
                auto* nd = q.front(); q.pop();
                row[ltr ? i : n - 1 - i] = nd->val;
                if (nd->left) q.push(nd->left);
                if (nd->right) q.push(nd->right);
            }
            res.push_back(row); ltr = !ltr;
        }
        return res;
    }
};
